module comp32(input a, input b, input c, output sum, output carry);
assign sum = a ^ b ^ c;
assign carry = (a & b) | (a & c) | (b & c);
endmodule

module comp22(input a, input b, output sum, output carry);
assign sum = a ^ b;
assign carry = a & b;
endmodule
